  startField: inp_start.text,   // e.g., 'start', 'start_time'
  endField: inp_end.text,       // e.g., 'end', 'end_time'
  durationField: inp_duration.text,  // e.g., 'duration'
	scheduleStartDate: datePick_start.selectedDate,
